TravellerConfig = {}
TravellerConfig.TravellerConfig = {}

function TravellerConfig:initConfig(configs)
    for _, config in pairs(configs) do
        local item = {
            id = tonumber(config.id),
            startPos = StringUtil.split(config.startPos, "#"),
            actor = tostring(config.actor),
            name = tostring(config.name),
            endPos = StringUtil.split(config.endPos, "#"),
            yaw = tonumber(config.yaw),
            randomPoolId = tonumber(config.randomPoolId),
            randomPoolParams = config.randomParams
        }
        self.TravellerConfig[item.id] = item
        ActorManager:createTravellerActor(item.id)
    end
end

function TravellerConfig:getConfigById(id)
    return self.TravellerConfig[id]
end

return TravellerConfig